use std::fmt::{self};
use std::iter::IntoIterator;

trait Processor {
    type Item;
    fn process_all<I: IntoIterator<Item = Self::Item>>(items: I) -> Vec<Self::Item>;
}

struct StringProcessor;

impl Processor for StringProcessor {
    type Item = String;
    fn process_all<I: IntoIterator<Item = String>>(items: I) -> Vec<String> {
        let mut result = Vec::new();
        for item in items {
            result.push(item.to_uppercase());
        }
        result
    }
}

struct NumberProcessor;

impl Processor for NumberProcessor {
    type Item = i32;
    fn process_all<I: IntoIterator<Item = i32>>(items: I) -> Vec<i32> {
        let mut result = Vec::new();
        for item in items {
            result.push(item * 2);
        }
        result
    }
}

fn main() {
    let string_list = vec![String::from("hello"), String::from("world")];
    let processed_strings = StringProcessor::process_all(string_list);
    println!("Processed Strings: {:?}", processed_strings);

    let number_list = vec![1, 2, 3];
    let processed_numbers = NumberProcessor::process_all(number_list);
    println!("Processed Numbers: {:?}", processed_numbers);
}

use std::fmt::{self, Display};
use std::iter::Product;

trait Processor {
    type Item;
    fn process_item(&self, item: Self::Item) -> String;
}

struct NumberProcessor {
    data: i32,
}

impl Processor for NumberProcessor {
    type Item = i32;
    fn process_item(&self, item: i32) -> String {
        format!("Processed number: {}", item * self.data)
    }
}

struct StringProcessor {
    prefix: String,
}

impl Processor for StringProcessor {
    type Item = String;
    fn process_item(&self, item: String) -> String {
        format!("{}-{}", &self.prefix, item)
    }
}

fn run_processing<P: Processor>(processor: &P, items: Vec<P::Item>) -> Vec<String> {
    items.into_iter()
        .map(|item| processor.process_item(item))
        .collect()
}

fn main() {
    let num_proc = NumberProcessor { data: 2 };
    let num_inputs = vec![1, 5, 10];
    let results1 = run_processing(&num_proc, num_inputs);
    println!("Results 1: {:?}", results1);

    let str_proc = StringProcessor { prefix: "Test".to_string() };
    let str_inputs = vec!["A".to_string(), "B".to_string()];
    let results2 = run_processing(&str_proc, str_inputs);
    println!("Results 2: {:?}", results2);
}

use std::collections::HashMap;

struct Processor<T> {
    data: HashMap<String, T>,
}

impl<T: Clone + std::fmt::Debug> Processor<T> {
    fn new() -> Self {
        Processor { data: HashMap::new() }
    }

    fn add_item(&mut self, key: String, value: T) {
        self.data.insert(key, value);
    }

    fn process_all(&self) -> Vec<T> {
        let mut results = Vec::new();
        for (_, value) in &self.data {
            results.push(value.clone());
        }
        results
    }
}

fn main() {
    let mut processor_i32 = Processor::<i32>::new();
    processor_i32.add_item("key1".to_string(), 42);
    processor_i32.add_item("key2".to_string(), 100);

    let results_i32 = processor_i32.process_all();
    println!("Processed i32 values: {:?}", results_i32);

    let mut processor_string = Processor::<String>::new();
    processor_string.add_item("name".to_string(), "Test".to_string());

    let results_string = processor_string.process_all();
    println!("Processed String values: {:?}", results_string);
}
